INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'consulting_agreement',
  'uk',
  1,
  'Consulting Services Agreement (United Kingdom)',
  'This Consulting Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, a company registered in England and Wales with registered address at {{party_a_address}} ("Client"), and {{party_b_company}}, with address at {{party_b_address}} ("Consultant").',
  'WHEREAS, Client desires to engage Consultant to provide professional consulting services as described herein;
WHEREAS, Consultant has the expertise and qualifications to provide such services;
NOW, THEREFORE, in consideration of the mutual covenants contained herein, the Parties agree as follows:',
  '[{"id":"engagement","title":"1. ENGAGEMENT AND SERVICES","content":"1.1 Engagement. Client hereby engages Consultant, and Consultant hereby accepts such engagement, to provide the consulting services described in {{services_description}} (the \"Services\").\n\n1.2 Standard of Performance. Consultant shall perform the Services with reasonable skill and care, in accordance with generally accepted professional standards, and in compliance with all applicable laws and regulations.\n\n1.3 Deliverables. Consultant shall deliver any deliverables specified in {{services_description}} in accordance with the timeline and specifications set forth therein.\n\n1.4 Client Cooperation. Client shall provide Consultant with reasonable access to personnel, information, and resources necessary for Consultant to perform the Services.\n\n1.5 Changes. Any changes to the Services must be agreed in writing by both Parties. If a change materially affects the scope, timeline, or fees, the Parties shall negotiate in good faith to agree appropriate adjustments.","type":"standard","order":1},{"id":"fees_payment","title":"2. FEES AND PAYMENT","content":"2.1 Fees. Client shall pay Consultant the fees set forth in {{services_description}}, which may include: (a) a fixed fee of {{payment_amount}}; and/or (b) time-based charges at a rate of {{hourly_rate}} per day/hour.\n\n2.2 Invoicing. Consultant shall submit invoices in accordance with the schedule specified in {{services_description}}, or if not specified, monthly in arrears.\n\n2.3 Payment Terms. Client shall pay undisputed invoices within 30 days of receipt. Late payments shall accrue interest at the rate of 8% above the Bank of England base rate, calculated daily.\n\n2.4 VAT. All fees are exclusive of VAT. Consultant shall add VAT at the applicable rate to invoices where required, and Client shall pay such VAT.\n\n2.5 Expenses. Unless pre-approved in writing by Client, Consultant shall bear all expenses incurred in performing the Services. Pre-approved expenses shall be reimbursed upon submission of reasonable documentation.\n\n2.6 Taxes. Consultant is responsible for all taxes arising from fees received, including income tax and National Insurance contributions.","type":"standard","order":2},{"id":"consultant_status","title":"3. CONSULTANT STATUS","content":"3.1 Independent Contractor. Consultant is an independent contractor and not an employee, worker, agent, or partner of Client.\n\n3.2 Control. Consultant shall determine the manner and means of performing the Services, subject to the requirements of this Agreement and any specifications provided by Client.\n\n3.3 IR35. The Parties intend this engagement to fall outside the off-payroll working rules (IR35). Consultant represents that the nature of this engagement supports such treatment. The Parties shall cooperate in any status determination required by law.\n\n3.4 Substitution. With Client''s prior written consent (not unreasonably withheld), Consultant may provide a suitably qualified substitute to perform Services. Consultant remains responsible for the substitute''s work.\n\n3.5 No Employee Benefits. Consultant is not entitled to Client''s employee benefits, including holiday pay, sick pay, pension contributions, or insurance.\n\n3.6 Other Engagements. Consultant may provide services to other clients, provided this does not conflict with Consultant''s obligations under this Agreement.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM AND TERMINATION","content":"4.1 Term. This Agreement commences on the Effective Date and continues until {{expiration_date}}, or if no date is specified, until the Services are completed, unless earlier terminated.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement by giving {{notice_period}} days'' written notice.\n\n4.3 Termination for Cause. Either Party may terminate immediately if the other Party: (a) materially breaches this Agreement and fails to remedy the breach within 14 days of written notice; (b) becomes insolvent, enters administration or liquidation; or (c) commits fraud or gross misconduct.\n\n4.4 Effect of Termination. Upon termination: (a) Consultant shall cease Services and deliver all Work Product and Client materials; (b) Client shall pay for Services properly performed through termination; (c) each Party shall return the other''s Confidential Information.\n\n4.5 Survival. Provisions intended to survive shall survive termination, including intellectual property, confidentiality, and liability provisions.","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY","content":"5.1 Work Product. \"Work Product\" means all materials, deliverables, inventions, and works created by Consultant in performing the Services.\n\n5.2 Assignment. Consultant assigns to Client all rights, title, and interest in the Work Product, including all intellectual property rights. Consultant shall execute any documents reasonably required to perfect such assignment.\n\n5.3 Background IP. Consultant retains ownership of pre-existing intellectual property (\"Background IP\"). To the extent Background IP is incorporated into Work Product, Consultant grants Client a perpetual, irrevocable, worldwide, royalty-free, sublicensable licence to use such Background IP as part of the Work Product.\n\n5.4 Moral Rights. Consultant waives moral rights in the Work Product to the extent permitted by the Copyright, Designs and Patents Act 1988.\n\n5.5 Third Party Materials. Consultant shall not incorporate third-party materials into Work Product without Client''s prior written approval and appropriate licences.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY","content":"6.1 Confidential Information. \"Confidential Information\" means all non-public information disclosed by one Party to the other that is designated confidential or should reasonably be understood to be confidential.\n\n6.2 Obligations. Each Party shall: (a) use Confidential Information only for purposes of this Agreement; (b) protect Confidential Information with reasonable care; (c) disclose Confidential Information only to personnel who need to know and are bound by confidentiality; and (d) notify the other Party of any suspected breach.\n\n6.3 Exclusions. Information is not Confidential Information if it: (a) is publicly available; (b) was known before disclosure; (c) is received from a third party without restriction; or (d) is independently developed.\n\n6.4 Required Disclosure. If required by law to disclose Confidential Information, the receiving Party shall (where permitted) give notice to allow the disclosing Party to seek protection.\n\n6.5 Return. Upon termination, each Party shall return or destroy the other''s Confidential Information.","type":"standard","order":6},{"id":"data_protection","title":"7. DATA PROTECTION","content":"7.1 Compliance. Each Party shall comply with applicable data protection legislation, including the UK GDPR and Data Protection Act 2018.\n\n7.2 Processing. To the extent Consultant processes Personal Data on behalf of Client: (a) Consultant shall process only in accordance with Client''s instructions; (b) Consultant shall implement appropriate security measures; (c) Consultant shall not transfer Personal Data outside the UK without appropriate safeguards; and (d) Consultant shall assist Client with data subject requests and regulatory obligations.\n\n7.3 Data Processing Agreement. If required, the Parties shall enter into a separate data processing agreement on terms that comply with applicable law.","type":"standard","order":7},{"id":"warranties_liability","title":"8. WARRANTIES AND LIABILITY","content":"8.1 Consultant Warranties. Consultant warrants that: (a) it has authority to enter into this Agreement; (b) Services will be performed with reasonable skill and care; (c) Work Product will not infringe third-party rights; and (d) it will comply with applicable laws.\n\n8.2 Client Warranties. Client warrants that it has authority to enter into this Agreement and will provide accurate information necessary for the Services.\n\n8.3 Limitation of Liability. Subject to Section 8.4: (a) neither Party shall be liable for indirect, consequential, or special damages; (b) total liability shall not exceed the fees paid or payable under this Agreement in the 12 months preceding the claim.\n\n8.4 Unlimited Liability. Nothing limits liability for: (a) death or personal injury from negligence; (b) fraud; (c) any matter which cannot be limited by law; or (d) intellectual property infringement.","type":"negotiable","order":8},{"id":"indemnification","title":"9. INDEMNIFICATION","content":"9.1 Consultant Indemnity. Consultant shall indemnify Client against third-party claims arising from: (a) Consultant''s negligence or wilful misconduct; (b) infringement of third-party intellectual property rights by the Work Product (except where caused by Client materials); or (c) Consultant''s breach of this Agreement.\n\n9.2 Client Indemnity. Client shall indemnify Consultant against third-party claims arising from Client materials that infringe third-party rights.\n\n9.3 Procedure. The indemnified Party shall: (a) promptly notify the indemnifying Party; (b) allow the indemnifying Party to control the defence; and (c) provide reasonable cooperation.","type":"negotiable","order":9},{"id":"general","title":"10. GENERAL PROVISIONS","content":"10.1 Governing Law. This Agreement is governed by the law of England and Wales.\n\n10.2 Jurisdiction. The courts of England and Wales have exclusive jurisdiction, except for injunctive relief which may be sought in any competent court.\n\n10.3 Notices. Notices must be in writing and delivered by hand, courier, Royal Mail signed-for, or email.\n\n10.4 Assignment. Neither Party may assign without prior written consent, except to a successor in a merger or acquisition.\n\n10.5 Entire Agreement. This Agreement constitutes the entire agreement. Amendments must be in writing signed by both Parties.\n\n10.6 Severability. Invalid provisions shall be modified to the minimum extent necessary.\n\n10.7 Waiver. Waivers must be in writing. Failure to enforce a right is not a waiver.\n\n10.8 Force Majeure. Neither Party is liable for delays beyond reasonable control.\n\n10.9 Third Party Rights. No rights under the Contracts (Rights of Third Parties) Act 1999.\n\n10.10 Counterparts. May be executed in counterparts, including electronically.\n\n10.11 Anti-Bribery. Each Party shall comply with the Bribery Act 2010.\n\n10.12 Insurance. Consultant shall maintain appropriate professional indemnity insurance.","type":"standard","order":10}]'::jsonb,
