on_date}}","label":"Expiration Date","description":"End date","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Rate","description":"Day or hourly rate","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Total Fee","description":"Total fee amount","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services Description","description":"Description of consulting services","category":"project","type":"textarea","required":false}]'::jsonb,
